    setContactResults([])
    setContactDropOpen(false)
    return
  }
  contactDebounce.current = setTimeout(async () => {
    try {
      const res = await fetch(`/api/contacts?q=${encodeURIComponent(q)}&limit=8`, {
        credentials: 'include',
